from copy import *

class Tal:

  def __init__(self, talet):
    self.nummer = talet

  def __repr__(self):
    return str(self.nummer)

lista = [Tal(3), Tal(4), Tal(1), Tal(-8), Tal(12)]
print("lista: ", lista)

alias = deepcopy(lista)
lista[0].nummer = 0

print("lista: ", lista)
print("alias: ", alias)
